/* Retorna o conteúdo pré-gerado para um tema, se existir.
   Ordem de busca (do mais confiável ao menos confiável):
   1) pelo código DC-GO do tema (t.dcgo) -> catalog.js -> lista de subtemas
      dessa habilidade -> primeiro subtema que tiver pré-pronto.
      Isso funciona mesmo quando o tema foi criado só pela habilidade
      (nome curto da matriz, ex. "Era Vargas e Estado Novo"), que nunca
      bateria por nome exato com o prebuilt.js.
   2) match exato do nome do tema (caso o tema já tenha o nome do
      subtema granular, ex. veio de "Partir da matriz" com subtema
      selecionado, ou foi renomeado manualmente para bater).
   3) match do nome ignorando maiúsculas/espaços.
*/
function getPrebuilt(t){
  if(!t) return null;
  if(t.dcgo && typeof SUBTEMAS!=='undefined'){
    const candidatos=[];
    const porDisc = t.disciplina && SUBTEMAS[t.disciplina+'|'+t.dcgo];
    const porCodigo = SUBTEMAS[t.dcgo];
    (porDisc||[]).forEach(o=>o&&o.s&&candidatos.push(o.s));
    (porCodigo||[]).forEach(o=>o&&o.s&&candidatos.push(o.s));
    for(const cand of candidatos){
      if(PREBUILT_OBJ[cand]) return PREBUILT_OBJ[cand];
    }
  }
  if(!t.nome) return null;
  const nome=t.nome.trim();
  if(PREBUILT_OBJ[nome]) return PREBUILT_OBJ[nome];
  const nomeLow=nome.toLowerCase();
  const key=Object.keys(PREBUILT_OBJ).find(k=>k.toLowerCase().trim()===nomeLow);
  return key?PREBUILT_OBJ[key]:null;
}

/* Aplica conteúdo pré-gerado a um tema que ainda não tem objetos gerados */
function applyPrebuiltIfEmpty(t){
  if(!t||!t.nome) return false;
  const pb=getPrebuilt(t);
  if(!pb) return false;
  const jaTemConteudo=t.obj && Object.keys(t.obj).some(k=>{
    const v=t.obj[k];
    if(!v) return false;
    if(k==='avaliacao'){
      // avaliacao só conta como preenchida se alguma sub-lista tem itens reais
      return typeof v==='object' && Object.values(v).some(a=>Array.isArray(a)?a.length>0:String(a||'').trim().length>0);
    }
    if(typeof v==='object' && !Array.isArray(v)) return Object.keys(v).length>0;
    return Array.isArray(v)?v.length:String(v).trim();
  });
  if(jaTemConteudo) return false;
  t.obj=Object.assign({},pb);
  persistTema(t);
  return true;
}

/* Popula PREBUILT em todos os temas vazios que têm conteúdo disponível. */
function seedAllPrebuilt(){
  let count=0;
  Object.values(temas).forEach(t=>{
    if(t && t.nome && applyPrebuiltIfEmpty(t)) count++;
  });
  if(count>0) console.log('[Leciona] PREBUILT aplicado a '+count+' tema(s).');
}
